local CS = CS
---@type LNativeHelper
local LNativeHelper = LNativeHelper

---@type LSdkMethod
local LSdkMethod = LXImport(".LSdkMethod")

local _cpEnums = {
    x3 = "x3",              -- 开发用的sdk， 是一个可以直接输入账号的
    madfun = "madfun",      -- 百奥海外
    qoo = "qoo",            -- 百奥-qoo海外
    qianxi = "qianxi",      --qianxi 东南亚
    zd = "zd",              --卓动 欧美
    gt = "gt",              --gt 日服
    haochen = "haochen",    --卓动 欧美 浩臣马甲,
    avg = "avg",            --百澳 avg
    steam = "steam",        --百澳 steam
}
---@class LSdkImpl
local LSdkImpl = LxClass("LSdkImpl", nil)
------------------------------------------------------------------------------------------
function LSdkImpl:Initialize()
    ---@type LSdkCpBase
    self._sdkCp = nil

    ---@type LSdkMadFunTrack
    self._sdkTrack = nil

    ---@type string
    self._platformSdk = nil

    local pfSdk = LGameSettings.platformSdk
    self._platformSdk = pfSdk
    self:CreateCp(pfSdk)
    self:CreateTrack(pfSdk)

    local msg = "===> sdk = " .. LGameSettings.platformSdk
    LogWarn(msg)
end

function LSdkImpl:Dispose()
    local sdkCp = self._sdkCp
    if sdkCp then
        sdkCp:Dispose()
        self._sdkCp = nil
    end

    if self._sdkTrack then
        self._sdkTrack:Dispose()
        self._sdkTrack = nil
    end
    table.dispose(self)
end


function LSdkImpl:CreateCp(platformName)
    if platformName == _cpEnums.x3 then
        self._sdkCp = require("LApp.sdk.cp.LSdkCpX3"):New()
    elseif platformName == _cpEnums.madfun then
        self._sdkCp = require("LApp.sdk.cp.LSdkCpMadFun"):New()
    elseif platformName == _cpEnums.qoo then
        self._sdkCp = require("LApp.sdk.cp.LSdkCpQoo"):New()
    elseif platformName == _cpEnums.qianxi then
        self._sdkCp = require("LApp.sdk.cp.LSdkCpQianxi"):New()
    elseif platformName == _cpEnums.zd then
        self._sdkCp = require("LApp.sdk.cp.LSdkCpZd"):New()
    elseif platformName == _cpEnums.haochen then
        self._sdkCp = require("LApp.sdk.cp.LSdkCpHaoChen"):New()
    elseif platformName == _cpEnums.gt then
        self._sdkCp = require("LApp.sdk.cp.LSdkCpGt"):New()
    elseif platformName == _cpEnums.avg then
        self._sdkCp = require("LApp.sdk.cp.LSdkCpAvg"):New()
    elseif platformName == _cpEnums.steam then
        self._sdkCp = require("LApp.sdk.cp.LSdkCpSteam"):New()
    else
        --self._sdkCp = require("LApp.sdk.cp.LSdkCpX3"):New()
        LogError("not support cp = "..tostring(platformName))
    end
    if self._sdkCp then
        self._sdkCp:SetName(platformName)
        self._sdkCp:SetImpl(self)
        self._sdkCp:Initialize()
    end
end

---region sdk track
function LSdkImpl:CreateTrack(platformName)
    if platformName == _cpEnums.madfun or platformName == _cpEnums.qoo then
        self._sdkTrack = require("LApp.sdk.track.LSdkMadFunTrack"):New()
    elseif platformName == _cpEnums.qianxi then
        self._sdkTrack = require("LApp.sdk.track.LSdkQianxiTrack"):New()
    elseif platformName == _cpEnums.zd then
        self._sdkTrack = require("LApp.sdk.track.LSdkZdTrack"):New()
    elseif platformName == _cpEnums.haochen then
        self._sdkTrack = require("LApp.sdk.track.LSdkHaoChenTrack"):New()
    elseif platformName == _cpEnums.gt then
        self._sdkTrack = require("LApp.sdk.track.LSdkGtTrack"):New()
    end
    if self._sdkTrack then
        self._sdkTrack:Initialize()
    end
end

function LSdkImpl:CallTrack(trackName, ...)
    local track = self._sdkTrack
    if not track then return end

    local func = track[trackName]
    if not func then return end

    func(track, ...)
end
---endregion sdk track

---region sdk base call
function LSdkImpl:CallMethod(methodName, ...)
    local sdkcp = self._sdkCp
    if not sdkcp then return end

    local method = sdkcp[methodName]
    if not method then return end

    return method(sdkcp, ...)
end

function LSdkImpl:OnCpNativeMessage(msg)
    if LOG_INFO_ENABLED then
        printInfoN2("SdkImpl", tostring(msg))
    end
    local methodName, args = LNativeHelper.Decode(msg)
    local method = self[methodName]
    if method ~= nil then
        method(self, args)
    else
        self:CallMethod(methodName, args)
    end
end

function LSdkImpl:SendCpNativeMessage(methodName, ...)
    if self._isDisposed then return end
    if string.isempty(methodName) then return end

    LNativeHelper.CallMethod(methodName, ...)
end

function LSdkImpl:GetCpNativeData(methodName, ...)
    if self._isDisposed then return end
    if string.isempty(methodName) then return end

    return LNativeHelper.GetNativeData(methodName, ...)
end

---@endregion sdk base call

