function LSdkImpl:OnSdkShowExitViewResult(args)
    local isSdkShow = tonumber(args[1]) or 0
    if isSdkShow > 0 then
        --sdk 显示了
        return
    end
    --显示游戏的退出界面
    self:ShowGameExitView()
end

function LSdkImpl:OnSavePngToPhoto(args)
    local isOk = toboolean(args[1])
    if gLGameUI then
        gLGameUI:OnScreenShotResult(isOk)
    end
end

function LSdkImpl:OnSysScreenShot(args)
