end

function LSdkImpl:DoChangeAccount()
    gModelGeneral:ShowUIOrdinTipLazy(120001,function()
        self:CallMethod(LSdkMethod.ChangeAccount)
    end,nil)
end

function LSdkImpl:ShowGameExitView(isLogout)
    if not gLxPatchCtrl then return end
    gLxPatchCtrl:ShowSysTips(15, "", function(selType)
        if selType == 2 then --关闭程序
            if CS.IsWebGL() then
                if LWxHelper.IsMiniGamePlatform() then
                    self:CallMethod("WxMiniGameExit")
                    return
                end
            end
            QuitGame()
        end
    end, "UIEtTip")
end


