--- WebView
------------------------------------------------------------------------------------------
function LSdkImpl:WebViewDestroy()
    self._webViewArgs = nil
    LNativeHelper.WebViewDestroy()
end
function LSdkImpl:WebViewShow(url, left, top, right, bottom, extraParam)
    if string.isempty(url) then return end

    if left == nil then
        local UScreen = UnityEngine.Screen
        local screenWidth = UScreen.width
        local screenHeight = UScreen.height

        --根据实际分辨率算位置
        local width = 640
        local height = 1136
        if screenHeight / screenWidth > height / width then
            --保持宽度
            height = height * screenHeight / screenWidth
        else
            --保持高度
            width = height * screenWidth / screenHeight
        end

        --400*600
        width = math.floor((width / 2 - 200) * screenWidth / width)
        height = math.floor((height / 2 - 300) * screenHeight / height)

        left = width
        top = height
        right = width
        bottom = height
    end

    print("webview margins = "..left.."|"..top.."|"..right.."|"..bottom)
    self._webViewArgs = { url = url, left = left, top = top, right = right, bottom = bottom }
    if extraParam then
        self:CallMethod(LSdkMethod.CallSdkWebViewCreateWithFlag,extraParam.flag, extraParam.ignore)
    else
        LNativeHelper.WebViewCreate()
    end

    if CS.IsOsWinOrEdit() then
        self:OnWebViewCreate()
    end
end

function LSdkImpl:OnWebViewCreate(args)
    local keeArgs = self._webViewArgs
    if keeArgs then
        LNativeHelper.WebViewSetMargins(keeArgs.left, keeArgs.top, keeArgs.right, keeArgs.bottom)
        LNativeHelper.WebViewSetVisibility(true)
        LNativeHelper.WebViewLoadUrl(keeArgs.url)
    else
        self:WebViewDestroy()
    end
end

function LSdkImpl:OnWebViewLayoutChange(args)
    FireEvent(EventNames.ON_WEB_LAYOUT_CHANGE, {
        left = tonumber(args[1]) or 0,
        top = tonumber(args[2]) or 0,
        right = tonumber(args[3]) or 0,
        bottom = tonumber(args[4]) or 0,
        oldLeft = tonumber(args[5]) or 0,
        oldTop = tonumber(args[6]) or 0,
        oldRight = tonumber(args[7]) or 0,
        oldBottom = tonumber(args[8]) or 0
    })
end

function LSdkImpl:OnWebViewUrlLoading(args)
    local bOk = toboolean(args[1])
    if not bOk then
        local sUrl = args[2] or ""
        local s,e = string.find(sUrl,"xhsdiscover:")
        if s and s == 1 then
            LNativeHelper.ShowToast(ccClientText(19302))
        else
            LNativeHelper.ShowToast(ccClientText(19301))
        end

    end
end
