function LSdkImpl:OnNotchFit(args)
    local notchEnable = toboolean(args[1])
    local notchWidth = tonumber(args[2]) or 0
    local notchHeight = tonumber(args[3]) or 0
    local manufacturer = tostring(args[4])
    printInfoN(string.format("OnNotchFit:%s,%s,%s,%s", notchEnable, notchWidth, notchHeight, manufacturer))
    LNotchUtil.ChangeNotchArea(notchEnable, notchWidth, notchHeight)
end
