--- 屏幕尺寸修改回调
function LSdkImpl:OnScreenResize(args)
    local sw = tonumber(args[1]) or 0
    local sh = tonumber(args[2]) or 0
    printInfoN(string.format("OnScreenResize:%s,%s", sw, sh))
    if sw > 0 and sh > 0 then
        if gLGameQuality then
            gLGameQuality:OnScreenResize(sw, sh)
        end
    end
end

return LSdkImpl